/* signng overlay styles — required by dialog / tooltip / popover (CDK overlay). */
@import '@angular/cdk/overlay-prebuilt.css';

/* Modal backdrop: opaque, pointer-blocking (clickjacking redress). */
.signng-dialog-backdrop {
  background: rgb(0 0 0 / 0.5);
}

/* Enter motion for every CDK-overlay panel (dialog, popover, dropdown, tooltip, sheet, drawer, select…)
   — one rule, no per-component edits. Disabled under prefers-reduced-motion (WCAG 2.3.3). */
@media (prefers-reduced-motion: no-preference) {
  @keyframes signng-pop-in {
    from { opacity: 0; transform: scale(0.97) translateY(-2px); }
    to { opacity: 1; transform: none; }
  }
  @keyframes signng-overlay-fade {
    from { opacity: 0; }
    to { opacity: 1; }
  }
  .cdk-overlay-pane > * {
    animation: signng-pop-in 0.16s cubic-bezier(0.16, 1, 0.3, 1);
  }
  .signng-dialog-backdrop {
    animation: signng-overlay-fade 0.2s ease-out;
  }
}
